#This script was generated by chat gbt to facilitate downloading the dataset Liar

from datasets import load_dataset

def load_liar_dataset():
    """
    Function to load the 'liar' dataset from Hugging Face with custom code enabled.
    
    Returns:
        dataset: The loaded dataset object.
    """
    try:
        # Load the dataset and allow remote code execution
        dataset = load_dataset("ucsbnlp/liar", trust_remote_code=True)
        print("Dataset loaded successfully.")
        return dataset
    except Exception as e:
        print(f"Failed to load dataset: {e}")
        return None

# Test the function
def test_load_liar_dataset():
    dataset = load_liar_dataset()
    if dataset:
        print("Test passed: Dataset loaded and returned.")
        # Optionally print a preview of the dataset
        print(dataset['train'][0])  # Print the first entry of the train split
    else:
        print("Test failed: Dataset not loaded.")

# Run the test
if __name__ == "__main__":
    test_load_liar_dataset()
